import { NextResponse } from 'next/server';
import PDFParser from 'pdf2json';
import axios from 'axios';
import { ref, getDownloadURL } from 'firebase/storage';
import { storage } from '@/lib/firebase';  // ✅ ONLY THIS LINE NEEDED!

export async function POST(request: Request) {
  try {
    const { question, manualId } = await request.json();
    
    // 1. Get PDF from Firebase
    const pdfRef = ref(storage, `manuals/${manualId}`);  // ✅ Uses shared storage
    const pdfUrl = await getDownloadURL(pdfRef);
    
    // 2. Download PDF
    const pdfResponse = await axios.get(pdfUrl, { responseType: 'arraybuffer' });
    
    // 3. Parse with pdf2json
    const pdfParser = new PDFParser();
    await new Promise((resolve, reject) => {
      pdfParser.on('pdfParser_dataError', reject);
      pdfParser.on('pdfParser_dataReady', (pdfData: any) => {
        const pdfText = pdfParser.getRawTextContent().slice(0, 4000);
        resolve(pdfText);
      });
      pdfParser.parseBuffer(pdfResponse.data);
    });
    
    // 4. DeepSeek API (fallback to mock)
    try {
      const deepseekResponse = await axios.post('https://api.deepseek.com/v1/chat/completions', {
        model: 'deepseek-r1',
        messages: [{
          role: 'user',
          content: `CAR MANUAL EXTRACT: "${pdfText}"
          Question: ${question}
          Answer using ONLY manual text. Include page numbers. Be precise.`
        }],
        max_tokens: 500,
        temperature: 0.1
      }, {
        headers: {
          'Authorization': `Bearer ${process.env.DEEPSEEK_API_KEY}`,
          'Content-Type': 'application/json'
        }
      });
      
      const answer = deepseekResponse.data.choices[0].message.content;
      return NextResponse.json({ success: true, answer, manualId });
    } catch {
      // Fallback to mock
      return NextResponse.json({
        success: true,
        answer: 'Consult your manual (DeepSeek temporarily unavailable)',
        manualId
      });
    }
  } catch (error) {
    return NextResponse.json({ error: 'Processing failed' }, { status: 500 });
  }
}



